import React from 'react';
import { Link, useParams } from 'react-router-dom';
import './Services.css';

const allServices = {
  'cloud-management': {
    icon: '☁️',
    title: 'Cloud Management',
    tagline: 'Scalable cloud infrastructure for the modern enterprise',
    desc: 'SHNOOR International provides end-to-end cloud management services including cloud strategy, architecture design, migration, and ongoing management. We work across AWS, Azure, and Google Cloud platforms to deliver secure, scalable, and cost-efficient infrastructure. Our certified cloud architects help you modernize legacy applications, adopt serverless computing, and optimize cloud spend with FinOps best practices. Whether you need a public, private, or hybrid cloud, we design solutions that align with your business goals and compliance requirements.',
    features: [
      'Cloud Strategy & Roadmap',
      'Infrastructure Migration',
      'Cloud Security & Compliance',
      'Cost Optimization (FinOps)',
      '24/7 Monitoring & Support',
      'Multi-cloud Management',
      'Serverless & Container Orchestration',
      'Disaster Recovery & Backup'
    ],
    benefits: [
      'Reduce IT infrastructure costs by up to 30%',
      'Achieve 99.99% availability with SLA-backed uptime',
      'Scale resources on-demand without upfront investment',
      'Meet GDPR, HIPAA, or SOC2 compliance effortlessly'
    ],
    image: 'https://images.unsplash.com/photo-1451187580459-43490279c0fa?w=800&q=80',
  },
  'enterprise-management': {
    icon: '🏢',
    title: 'Enterprise Management',
    tagline: 'Streamline operations with powerful ERP solutions',
    desc: 'We deliver comprehensive enterprise management solutions including ERP implementation, business process optimization, and system integration. Our experts help organizations modernize their operations and improve efficiency across departments. From SAP S/4HANA to Microsoft Dynamics and Oracle NetSuite, we tailor solutions that automate workflows, provide real-time analytics, and unify data silos. Our change management methodology ensures user adoption and minimal disruption.',
    features: [
      'ERP Implementation (SAP, Oracle, Microsoft)',
      'Process Automation & Workflow Design',
      'System Integration (API, ESB)',
      'Change Management & Training',
      'Business Analytics & Reporting',
      'Digital Transformation Roadmap',
      'Legacy System Modernization',
      'Supply Chain Management'
    ],
    benefits: [
      'Increase operational efficiency by 40%',
      'Reduce manual errors through automation',
      'Gain real-time visibility into business performance',
      'Enable data-driven decision making'
    ],
    image: 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=800&q=80',
  },
  'data-ai': {
    icon: '🤖',
    title: 'Data & Artificial Intelligence',
    tagline: 'Turning data into your most powerful business asset',
    desc: 'Harness the power of big data and AI with SHNOOR’s data science and analytics services. From data engineering to predictive modeling and AI-powered applications, we help you extract meaningful insights to drive smarter decisions. Our team builds custom machine learning models, deploys LLM-based assistants, and creates self-service BI dashboards. We also support MLOps to scale models from experimentation to production reliably.',
    features: [
      'Data Engineering & Pipelines',
      'Machine Learning Models (Regression, Classification, Clustering)',
      'Predictive & Prescriptive Analytics',
      'Business Intelligence (Power BI, Tableau)',
      'Natural Language Processing (NLP)',
      'AI-Powered Automation (RPA + AI)',
      'LLM Integration (OpenAI, Claude, Gemini)',
      'Data Governance & Quality'
    ],
    benefits: [
      'Uncover hidden patterns to improve revenue',
      'Reduce churn with predictive customer insights',
      'Automate routine decisions with AI',
      'Achieve 360° view of your business data'
    ],
    image: 'https://images.unsplash.com/photo-1555949963-aa79dcee981c?w=800&q=80',
  },
  'it-consulting': {
    icon: '👥',
    title: 'IT Consulting & Staffing',
    tagline: 'Expert IT talent when and where you need it',
    desc: 'SHNOOR connects businesses with top IT professionals across multiple domains. Whether you need a single specialist or an entire team, our staffing solutions are tailored to match your technical requirements and corporate culture. We maintain a rigorous vetting process – including technical assessments, soft skill evaluation, and background checks – to ensure you get only the best. Our global talent pool covers developers, architects, project managers, and C-level executives.',
    features: [
      'IT Staff Augmentation (onsite/offshore)',
      'Permanent Placement',
      'Contract-to-Hire Staffing',
      'Executive Search & Leadership Hiring',
      'Technical Assessment & Skills Gap Analysis',
      'Onboarding & Retention Support',
      'Remote Team Integration',
      'Payroll & Compliance Management'
    ],
    benefits: [
      'Fill critical roles in under 2 weeks',
      'Reduce hiring costs by 50%',
      'Scale teams up or down with flexibility',
      'Access pre-vetted talent from India, UAE, and Europe'
    ],
    image: 'https://images.unsplash.com/photo-1600880292203-757bb62b4baf?w=800&q=80',
  },
  'background-verification': {
    icon: '🔍',
    title: 'Background Verification',
    tagline: 'Build trust with thorough, reliable verification',
    desc: 'Protect your organization with our professional background verification services. We help you validate candidate credentials, screen criminal records, verify employment history, and ensure every hire meets your company’s standards. Our team uses both automated and manual checks with court record searches, education institution verification, and reference interviews. We serve clients in India, GCC countries, Southeast Asia, and the US.',
    features: [
      'Criminal Record Check (national & international)',
      'Employment History & Gap Verification',
      'Education Credential Check (universities, degrees)',
      'Professional Reference Verification',
      'Identity & Address Verification',
      'Global Sanctions & Watchlist Screening',
      'Credit Check (where applicable)',
      'Continuous Monitoring (for existing employees)'
    ],
    benefits: [
      'Reduce hiring risk by 70%',
      'Avoid costly negligent hiring lawsuits',
      'Ensure compliance with local labor laws',
      'Build a culture of trust and safety'
    ],
    image: 'https://images.unsplash.com/photo-1614064641938-3bbee52942c7?w=800&q=80',
  },
  'healthcare': {
    icon: '🏥',
    title: 'Healthcare IT',
    tagline: 'Technology solutions tailored for healthcare providers',
    desc: 'SHNOOR offers specialized IT solutions designed for hospitals, clinics, and healthcare organizations. From electronic health records to telemedicine platforms, we help healthcare providers deliver better patient outcomes through technology. Our solutions are HL7/FHIR compliant, interoperable, and built with patient data privacy as a top priority (HIPAA, GDPR, local health data laws). We also offer AI-assisted diagnostics and patient engagement portals.',
    features: [
      'Electronic Health Records (EHR/EMR)',
      'Telemedicine & Remote Patient Monitoring',
      'Hospital Management System (HMS)',
      'Medical Data Analytics & Population Health',
      'HIPAA / GDPR Compliance Audit',
      'Healthcare Interoperability (HL7, FHIR)',
      'AI Diagnostics Support',
      'Patient Portal & Appointment Scheduling'
    ],
    benefits: [
      'Improve patient care coordination',
      'Reduce administrative burden by 35%',
      'Enable secure remote consultations',
      'Achieve regulatory compliance with confidence'
    ],
    image: 'https://images.unsplash.com/photo-1576091160399-112ba8d25d1d?w=800&q=80',
  },
  'sap-outsourcing': {
    icon: '⚙️',
    title: 'SAP Outsourcing',
    tagline: 'Full-spectrum SAP support and implementation',
    desc: 'Our SAP certified consultants deliver end-to-end SAP services including implementation, customization, migration, and ongoing support. We cover all major SAP modules to help businesses optimize their enterprise operations. Whether you are on SAP ECC or transitioning to S/4HANA, we provide expert guidance, custom ABAP development, and integration with third-party systems. We also offer managed services – helpdesk, enhancements, and upgrade projects.',
    features: [
      'SAP Implementation (All Modules)',
      'SAP S/4HANA Migration & Conversion',
      'SAP MM / SD / FI / CO / HR / PP',
      'Custom ABAP Development & RICEFW',
      'SAP Basis & Security Administration',
      'SAP Fiori / UI5 Development',
      'SAP Support & AMS (Application Management)',
      'SAP Training & Change Enablement'
    ],
    benefits: [
      'Reduce SAP TCO by 40% with outsourcing',
      'Accelerate S/4HANA migration by 50%',
      '24/7 support with guaranteed SLAs',
      'Access a bench of certified SAP consultants'
    ],
    image: 'https://images.unsplash.com/photo-1518770660439-4636190af475?w=800&q=80',
  },
  'app-development': {
    icon: '💻',
    title: 'App Development',
    tagline: 'Custom software built for your unique needs',
    desc: 'SHNOOR’s development team builds high-performance web and mobile applications tailored to your business goals. From concept to deployment, we deliver scalable, user-friendly applications using modern technologies. We follow agile methodologies, design thinking, and CI/CD pipelines to ensure fast iterations and high quality. Our expertise includes React, Angular, Vue.js, Node.js, .NET Core, Python/Django, and Flutter for cross-platform mobile apps.',
    features: [
      'Web Application Development (SPA, PWA)',
      'Mobile App (iOS, Android, Flutter, React Native)',
      'UI/UX Design & Prototyping',
      'API Development & Third-Party Integration',
      'Quality Assurance (Manual + Automated)',
      'DevOps & Cloud Deployment (AWS, Azure)',
      'Legacy App Modernization',
      'Maintenance & Support'
    ],
    benefits: [
      'Launch MVPs in 6–8 weeks',
      'Scalable architecture that grows with you',
      'Seamless integration with your existing systems',
      'Post-launch retention and feature updates'
    ],
    image: 'https://images.unsplash.com/photo-1587620962725-abab19836100?w=800&q=80',
  },
};

const serviceList = Object.entries(allServices).map(([slug, s]) => ({ slug, ...s }));

export default function Services() {
  const { slug } = useParams();
  const service = slug ? allServices[slug] : null;

  if (service) {
    return (
      <div className="service-detail">
        <section className="page-hero">
          <div className="page-hero-overlay" style={{ backgroundImage: `url(${service.image})` }} />
          <div className="container page-hero-content">
            <span className="section-tag">Services</span>
            <h1>{service.icon} {service.title}</h1>
            <p>{service.tagline}</p>
          </div>
        </section>

        <section className="section-padding">
          <div className="container service-detail-grid">
            <div className="service-detail-main">
              <h2>Overview</h2>
              <p>{service.desc}</p>

              <h3 style={{ marginTop: '32px', marginBottom: '20px' }}>Key Features</h3>
              <div className="features-grid">
                {service.features.map((f, i) => (
                  <div key={i} className="feature-item">
                    <span className="feature-check">✓</span>
                    <span>{f}</span>
                  </div>
                ))}
              </div>

              <h3 style={{ marginTop: '32px', marginBottom: '20px' }}>Key Benefits</h3>
              <div className="features-grid">
                {service.benefits.map((b, i) => (
                  <div key={i} className="feature-item">
                    <span className="feature-check">★</span>
                    <span>{b}</span>
                  </div>
                ))}
              </div>

              <div style={{ marginTop: '36px', display: 'flex', gap: '12px', flexWrap: 'wrap' }}>
                <Link to="/contact" className="btn-primary">Get Started</Link>
                <Link to="/services" className="btn-gold">All Services</Link>
              </div>
            </div>

            <div className="service-detail-sidebar">
              <div className="sidebar-card">
                <h4>All Services</h4>
                {serviceList.map((s) => (
                  <Link
                    key={s.slug}
                    to={`/services/${s.slug}`}
                    className={`sidebar-link ${slug === s.slug ? 'active' : ''}`}
                  >
                    <span>{s.icon}</span> {s.title}
                  </Link>
                ))}
              </div>
              <div className="sidebar-cta">
                <h4>Need Help?</h4>
                <p>Talk to our experts about the best solution for your business.</p>
                <Link to="/contact" className="btn-primary" style={{ marginTop: '16px', width: '100%', justifyContent: 'center' }}>
                  Contact Us
                </Link>
              </div>
            </div>
          </div>
        </section>
      </div>
    );
  }

  return (
    <div className="services-page">
      <section className="page-hero">
        <div className="page-hero-overlay" />
        <div className="container page-hero-content">
          <span className="section-tag">What We Offer</span>
          <h1>Our Services</h1>
          <p>Comprehensive IT and global trade solutions for modern businesses</p>
        </div>
      </section>

      <section className="section-padding">
        <div className="container">
          <div className="services-listing">
            {serviceList.map((s, i) => (
              <div key={i} className={`service-listing-card ${i % 2 === 1 ? 'reverse' : ''}`}>
                <div className="slc-image">
                  <img src={s.image} alt={s.title} />
                </div>
                <div className="slc-content">
                  <span className="slc-icon">{s.icon}</span>
                  <h2>{s.title}</h2>
                  <p className="slc-tagline">{s.tagline}</p>
                  <p>{s.desc.substring(0, 220)}...</p>
                  <div className="slc-features">
                    {s.features.slice(0, 4).map((f, fi) => (
                      <span key={fi} className="slc-feature-tag">{f}</span>
                    ))}
                  </div>
                  <Link to={`/services/${s.slug}`} className="btn-primary" style={{ marginTop: '20px' }}>
                    Learn More →
                  </Link>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>
    </div>
  );
}
